Javascript.logic:
var value = Services.getValue(LastWarrantNumber.dataBinding);
if (!CaseManUtils.isBlank(value))
{
    Services.setValue(REPRINT_PAGE, "");
	searchWarrants(LastWarrantNumber);
	validateReprint();
}

Javascript.miscCode:

LastWarrantNumber.onSuccess = function(dom) {
    if(dom != null) {
        var node = dom.selectSingleNode("/ds/Warrants");
        Services.replaceNode(SEARCH_RESULTS_XPATH_LAST, node);
        
        var count = Services.countNodes(SEARCH_RESULTS_XPATH_LAST + "/Warrant");
        if(count == 0) {
           alert("Last Warrant Number\r\n" + Messages.NO_RESULTS_MESSAGE); 
        } else if(count >= 1) {
        }
    }
}
